choose.when:
UPDATE  /* @SQLID=SUB0202_0304-01_2#Sql002 */
    DEPOSIT_TRANSFER
SET
    API_ERROR_CODE = null
    , API_STATUS_CODE = #{req.responseCode}
    , API_MESSAGE = null
    , UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    , UPDATE_USER = #{req.userId}
WHERE
    DEPOSIT_TRANSFER_NO = #{req.depositTransferNo}

choose.otherwise:
UPDATE  /* @SQLID=SUB0202_0304-01_2#Sql002 */
    DEPOSIT_TRANSFER
SET
    API_ERROR_CODE = #{req.code}
    , API_STATUS_CODE = #{req.responseCode}
    , API_MESSAGE = SubStr(#{req.errMessage},1,100)
    , UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    , UPDATE_USER = #{req.userId}
WHERE
    DEPOSIT_TRANSFER_NO = #{req.depositTransferNo}
